(window.webpackJsonp=window.webpackJsonp||[]).push([[48],{313:function(v,_,t){"use strict";t.r(_);var a=t(13),p=Object(a.a)({},(function(){var v=this,_=v._self._c;return _("ContentSlotsDistributor",{attrs:{"slot-key":v.$parent.slotKey}},[_("h1",{attrs:{id:"重蹈覆辙"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#重蹈覆辙"}},[v._v("#")]),v._v(" 重蹈覆辙")]),v._v(" "),_("h2",{attrs:{id:"芒种"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#芒种"}},[v._v("#")]),v._v(" 芒种")]),v._v(" "),_("p",[v._v("“一想到你我就/空恨别梦久/烧去纸灰埋烟柳”")]),v._v(" "),_("p",[v._v("又到了一年一度的芒种时节，也就是曾经，每一年高考的时候。在大学的下半场里，高考已经成为了一个渐渐在记忆里淡却的词，但它也终是应该铭记的吧，毕竟，是上一个阶段的结束，也是这一个阶段的开始。也许我还是应该感谢碑亭巷口长江路边奋斗的日子，感谢玄武湖下西家大塘落幕的钟声，感谢当初的运气和选择，至少有了一个不错的故事开始。")]),v._v(" "),_("p",[v._v("看见表白墙上说：“在我发出消息的一刻，我就没想过还能跟你做朋友”。我早已清楚了这句话，于是便没有勇气去想。这种犹豫贯穿了后来的三年时光，也许这便是我性格里最大的弱点：内心深处的怯懦，和不愿改变现状的保守。可是，当现状本就脆弱地无法保持，那若不去改变，便只能看着它土崩瓦解，而且是以你最不想看到的局面瓦解。")]),v._v(" "),_("p",[v._v("可是这样的经历，却让我在之后的日子里更加保守，更加小心翼翼。我总是天真的以为，既然没有表白，那就不会失败，也许还能继续做着朋友，直到一切时机都成熟的时候便自然圆满了。可是，人总是难以一帆风顺，每一个引人注目的果实总会勾起许许多多觊觎的目光。时机永远会在成熟之前被意外破坏，果实在总在你的犹豫之中归于他人之手。世界不是一个人的世界，成功却只有一个人能成功。")]),v._v(" "),_("p",[v._v("成年人的世界里没有不劳而获，韭菜的奋斗和后浪的“拼搏”并不分贵贱。我愿意为我想要的东西奋斗，却总是在自己的欲望面前犹疑，可成功需要的运气来自于时机。如果没有把握住去年的一连串机遇，可能就没有我经历中唯一能看的几笔。就像今年的危机，又有谁能事先想到这样的开局？敢于承担竞赛失败的后果，却不敢成为情感危机的败例。其实本就一无所有，却为什么不愿意。")]),v._v(" "),_("p",[v._v("就仿佛那研究生的愿望，心中的白月光。尽管很难，但也想要去尝试一下。可是随着时间的推移，日益忙碌的课程让我信心游移。也许不去动摇选择坚定结局会是胜利，但胆怯的内心总想让我选择放弃。生活艰难，网课尤甚。实验不会，作业手残。可能这终是每一个大三学子必须面对的过程，在这赤裸裸的现实面前，理想或者妥协，没有第三种选择，也就是说，无可逃避。")]),v._v(" "),_("p",[v._v("据说，避免失败的方法有这么几项：1.不要回忆过去，2.不要好为人师，3.坚定目标前行。我已经失去了前两种机会，于是便只剩了最后这么一个可能性。目标是什么？目标对我的诱惑有多大？实现目标又应该做些什么？但愿我能解决这三个困扰了许久的问题，也但愿感情的魔咒就此结束，不再有下一次，看见自己感觉到喜欢的姑娘换上了情头，却不是和自己。")]),v._v(" "),_("p",[v._v("“暧昧就是所有人都以为你们在一起了，只有你清楚的知道你们之间的距离。”所有的暧昧里，总有人要迈过那一步距离，不然一切看上去的美好，都终会烟消云散。但前提是，得有暧昧。")]),v._v(" "),_("h2",{attrs:{id:"梅雨"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#梅雨"}},[v._v("#")]),v._v(" 梅雨")]),v._v(" "),_("p",[v._v("南京正式入梅了，是二十年来最早的一次。不得不说，2020年的气候相当的不正常，一切时令都在提前，跑着步子迈进了夏天。也许是因为澳大利亚烧了半年的火，也许是病毒之下销声匿迹的人烟。在这落雨的黄梅时节里，压抑的空气沉闷着熏蒸的暑气，让本就烦躁的学子更为不安了起来。考试连考试，课设夹实验，网课胡乱听，作业无止境。于是乎，索性啥也不做，倒也不失为一种解脱。")]),v._v(" "),_("p",[v._v("那么便收拾收拾电脑里的文件吧。自去年换了电脑以来，旧电脑里的文件就一直存在硬盘的某个角落里，几乎从未打开过。丑陋的课程设计界面，至今也想不通到底是用什么做出来的(现在想想好像是纯WindowsAPI手撸)，滑稽的思政课刷题软件(MySQL+Tkinter)，以及重复率高达9%的建模论文。看见Python，数模与单片机的笨拙起步，花样百出的各种实验，不禁为现在的怠惰而羞愧。曾经保存的一段聊天记录，记载着众多18大佬们曾经青涩的模样，就如同媛媛学姐那为人称道的别致的美丽。")]),v._v(" "),_("p",[v._v("最终又找见了一份去年一月的好友名单和已删记录。虽然仅仅一年多，但一切早已物是人非。曾经简单的快乐已经难以继续，就如同昔日的列表，仅仅只有64人留到了今天。仿佛活跃在社交场的圆圈中心，心中却是分外的孤独。眼前的路终究还是得一个人走，需要的也许并不是朋友。就像有的时候，我对你很好，尽我所能的帮你。但这不一定意味着，我会把你当朋友。朋友是什么？朋友是关键时刻能指望帮得上忙的人吗？朋友是经常一起嘻嘻哈哈一起玩梗一起互相吹捧的人吗？对于这些，我会对他们很好，但不表示会把他们当成朋友。")]),v._v(" "),_("p",[v._v("朋友可能交情非常淡薄，但却能听懂我表面之下潜藏的情绪，能够排解我内心难以化解的忧愁和焦虑。这样的朋友并不好找，但总有那么人会的。这也许就是我的列表经常发生更替的原因吧。那删去的103个好友或许并非有不满或怨言，也许只是单纯的没有了未来的预期。就像后来逐渐迈入我生活的124位好友，在往后的日子里，他们又有多少能留的下来呢？我可能会经常帮别人的忙，但我不喜欢被人依赖的感觉。")]),v._v(" "),_("p",[v._v("当我喜欢上一个人的时候，我的心里就不会再有第二个人的位置，直到时间冲刷了热情，或者机会彻底地失去。但就算这样，我也依然会记得，也依然不会产生任何的一点厌恶。就如同曾经天真的向往：未曾表白失败过，便还可以继续做朋友。但可惜的是，终究话还没出口，她就已经牵上了别人的手。也有的时候，到了最后，我也不知道，我究竟有没有喜欢过。")]),v._v(" "),_("h2",{attrs:{id:"千古"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#千古"}},[v._v("#")]),v._v(" 千古")]),v._v(" "),_("p",[v._v("2020年6月22日，距离考研开始只剩了180天。课设和实验依旧紧紧束缚着思维和时间，让所谓的雄心壮志都化为了看得见摸不着的轻烟。脑子里本就虚无缥缈的极限微分积分级数在matlab和HFSS的打击下早已忘的干干净净，倒是计组和操作系统在单片机和DSP的呼唤下依然清晰。零零碎碎的琐事搅得人心烦意乱，情绪像这梅雨季节的天气一般低沉。不是每个赌怪都能从二十块赢到三千七百万，十七张牌也可以被阿姨反手泼一身卡布奇诺。我的底牌似乎没有十七张那么多，但好像赌本也不止二十块，所以赌赢的概率也是有的，尽管不大。不过还好，180天的时间还够我再多攒一点底牌。")]),v._v(" "),_("p",[v._v("最近又开始养火花了，上一次的话可能是去年下半年吧。基本上火花都是忙着忙着就断了，断着断着就没了，就像我一直以来各种奇奇怪怪的感情线一样。再早以前还是大一的时候养过两个巨轮，小火到大火小船到大船这样子，至今还是在我亲密度排行榜的榜首。最早的一个巨轮已经在列表里消失很久了，过去一年多跟以前经贸的同学们疏远了很多很多，渐渐就完全变成陌生人了。其实人生也是这样，来来又去去，最后能剩下的朋友也没有几个，可能一度无话不说的所谓好朋友照面都不会打个招呼，但那个很久才会问候一下的人才是内心的真正依靠，在困难的时候最会想起的人。人生总有比较艰苦的时候，也许总还是需要一个依靠才能撑下去的吧。")]),v._v(" "),_("p",[v._v("很羡慕列表里每天过的很充实很充满正能量的那些人，每天读一首诗，每天推一首歌，每天背几百单词，每天学点python。心态积极又乐观的时候，只要足够勤奋肯努力，运气总是会眷顾着的。而当状态不好的时候，运气就会总是背道而驰，不论做什么都做不出来，很快就什么也不想做了，就像我现在的状态一样。我和学习能力50的大佬的差别，并不在于我的学习能力只有5，而是我的状态决定了我只能发挥出5的学习力。想念学校，想念综一406的实验室，想念曾经在那里发愤图强的自己。")]),v._v(" "),_("p",[v._v("等到忙完这段时间，希望能好好修复一下心态吧。忙碌总是很容易让人的心态趋于崩溃，而这样的心态则会进一步加剧这种忙碌，直到一切都搞砸之后黯然收场。今年的毕业典礼在这样一个情况下草草收场了，我们也即将在牛头冲度过最后一年的时光。再过些年，我们就会像破烂的老宣城站和阴暗的临时图书馆一样，消失在高铁站的瓦砾堆里，隐藏在敬亭学堂的角落里，最后散落在历史的烟云里。所谓的期待，到了最后的时候，却已经索然无味。三年过去，仿佛一切都已不像从前，但又好像一切依然是从前的模样，似有期待，却又不愿相信期待。")]),v._v(" "),_("p",[v._v("若流芳千古，爱的人却反目，错过了幸福，谁又为我在乎？若贻笑千古，因为爱的痴迷又糊涂，也不悔做你的信徒。")]),v._v(" "),_("h2",{attrs:{id:"醒来"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#醒来"}},[v._v("#")]),v._v(" 醒来")]),v._v(" "),_("p",[v._v("当时光走到岁月的末梢，总会觉得一切的一切都像是一场刚刚醒来的梦。抑或是，还在梦里，没有醒来。")]),v._v(" "),_("p",[v._v("时光倒退回2017年的9月，北京来的K101次列车在下午两点晃晃悠悠离开了南京站，驶上老旧的宁芜铁路去向了皖南。走出破败的火车站，坐上学校的大巴，人去楼空的商学系迎新点在夕阳下颇有几分萧瑟。敬亭学堂一楼的临时图书馆散发着艰苦奋斗的味道，可我除了借过几本四六级资料外就再也没去过那里，反倒是去过宛陵湖畔的宣城图书馆体验悠闲的氛围。僻静的小城里，记录着故事的开头，安详又美好。")]),v._v(" "),_("p",[v._v("看着图书馆大楼开业，看着新火车站投用，看着城市一天天的变化着，有空爬爬山，或者在大街小巷穿行，偶尔打打比赛，保守着心中卑微的喜欢，过轻松而悠闲的日子。也许在大一最后的时光里有那么些无奈和伤悲，但终究不过是一场照进了现实里的梦境。故事，它还是有的啊。")]),v._v(" "),_("p",[v._v("可电信科的日子才真正教育了我工业大学之所以为工业大学。忙碌的日子里无暇顾及到感情，仅仅生存就要拼尽全力。我练了好久，却也无济于事，终究还是面对着挂科的结局。星空的璀璨，在于它的梦幻。生如流星，在宇宙间走走停停，遇见也就够了，还要奢求什么呢。遇见而后喜欢，却终究没有缘分，那便藏在心底不要说出口，起码还能做朋友。海边的风铃声依然悦耳动听，清晨的露珠也依然璀璨靓丽。情不知所起，一往而深，却总戛然而止，仿佛梧桐雨落的凄清。")]),v._v(" "),_("p",[v._v("既然学业注定无所斩获，那便在学习以外的地方消遣自己，沉迷比赛和旅行，在层层叠叠的证书间迷失自我，在浩浩荡荡的山水间放纵灵魂。半年一遇的喜欢终不敌注定孤身的魔咒，就让永恒时间刻下你的模样，在心的深处。寄情于国风的词曲，书写着难懂的诗句。喜欢就是喜欢了，那又怎样。当我把它说出口的时候，一切都已经不重要了。注定不会有什么结果的感情，最多也不过是一场无所谓的闹剧。")]),v._v(" "),_("p",[v._v("转瞬间，2020年的一半就过完了，相遇于惊艳的外表，相识于博学的灵魂，却最终相知于敏感的内心。但愿这又是一场空，只不过是宿命注定的相逢。无欲无我，勿贪勿念。愿岁月静好，只待有缘人。等待终究会有结果，就像这高铁般，在你最意想不到的时候里，不期而至。")]),v._v(" "),_("h2",{attrs:{id:"光明"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#光明"}},[v._v("#")]),v._v(" 光明")]),v._v(" "),_("p",[v._v("当移动互联网悄然走进了时代，当后浪们拥有了获得信息的自由时，殊不知，大数据与算法这只看不见的黑手，却在一点一点将着自由的光芒蚕食。当你看到的都是你爱看的，你听到的都是你爱听的，这时候的你，又会变成什么样子呢？")]),v._v(" "),_("p",[v._v("早在战国时期，邹忌就已经明白了“兼听则明，偏听则暗”的道理。“吾妻之美我者，私我也；妾之美我者，畏我也；客之美我者，欲有求于我也。”唐太宗李世民也深谙这个道理，他重用说话不中听的魏征，就是为了“兼听则明，偏听则暗”。可是随着时代的变迁，这些中华民族的传统却在互联网的大潮中节节败退。优良的传统在埋没，在丢弃。算法和大数据在不知不觉间做到了封建统治者几千年都无法做到的事——让民众自愿的去选择去相信他们所看到的一切。因为，他们所看到的一切，都是他们爱看的。")]),v._v(" "),_("p",[v._v("随着互联网时代的进步，我们也能发现一个现象，整个互联网世界的戾气都在不断变重。当你每天看到的都是一样的东西的时候，你就会日渐盲目地迷信它。就像题目中写到的同声相应，同气相求。人们总是关注自己喜爱的人和事，久而久之，就会被同类信息所环绕、所塑造。你已经不再是你自己，而是被你接受的信息，接受的环境塑造出的你。就像我们不能理解肖战粉丝们的狂热举动一样，他们也不能理解，为什么这个世界上还会有跟他们意见不一样的人，还有不喜欢甚至诋毁他们的“哥哥”的人。就像我们不能理解为什么特朗普一条推特发出去，就有不在少数美国愚民喝起消毒液，他们总是盲目相信，大统领说的一切都是对的。这种感受，是一种潜移默化的过程，外人难以理解，更无法体会。")]),v._v(" "),_("p",[v._v("在智能互联网时代，你的未来真正掌握在了自己手中。多去看阳光正能量的内容，你的世界里就会充满阳光和正能量；看多了阴暗和丑恶世界的人，内心也终究会变得阴暗丑恶。但，这种改变，是从哪里开始的呢？是一次从心所欲的浏览，还是一串惺惺相惜的点赞？是一回情不自禁的分享，还是一场突如其来的感动？在现代互联网的世界里，当你看到的世界是光明的，你的世界便是光明的；当你看到的世界是阴暗的，你的世界便是阴暗的。")]),v._v(" "),_("p",[v._v("所以，与其去陷入黑暗，不如去拥抱光明。我们要看到，我们的世界里不仅仅有那些只会推诿责任一问三不知的干部，还有李文亮医生，钟南山院士这样不畏生死勇往直前的人。我们要看到，我们的世界里不仅仅有那些网络上怼天怼地的键盘侠，还有罗翔教授，李子柒这样的正能量博主。我们的世界里不仅仅有阴暗，还有着更多的光明。所以，去拥抱光明吧，后浪！")]),v._v(" "),_("h2",{attrs:{id:"京城往事"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#京城往事"}},[v._v("#")]),v._v(" 京城往事")]),v._v(" "),_("p",[v._v("当T65次列车越过西四环边的丰台站缓缓驶进城里，眼前的一切变得模糊又熟悉。奢华的北京南站并不是铁路的尽头，龙潭公园和东二环的车水马龙氤氲在眼帘里。嘈杂的人声鼎沸在广场上，拖着行李越过天桥来到那胡同里给窗口递上10元，把许久未用的市政交通一卡通激活。122路的老巫婆和403的小财神挤在那里，却久久没有发车的意思，等了许久才听着柴油机隆隆的响，便刷上四角钱，数着一个个熟悉的站名，去见，那许久未见的外公外婆。北京，一个既非我出生非我成长的地方，却伴随了我十余年的记忆，在每一个重要的时刻里，从未缺席。")]),v._v(" "),_("p",[v._v("十四年前的冬天，我还是一年级的小萌新。从重庆出发坐了一天的火车，来到了北京。崭新的西客站旁，是新婚不久的小姨的新家。宽敞明亮的大房子里，承载着我童年的记忆。动物园和天安门还是那么的新鲜，国旗飘扬在风里。龙潭公园的庙会也是第一次去，人潮如织里感觉也甚是新鲜。神州大一路那时还到马官营，1462次硬卧也还是木质的床铺。这，便是遥远的京城记忆的开始。")]),v._v(" "),_("p",[v._v("十二年前的冬天，当南方还在大雪的覆盖里，刚刚转学回南京的我便再一次来到了北京。刚刚出生不久的表妹还在襁褓里，张灯结彩的冬日里感受着团圆年的气息。冒着寒风去北四环工地里看着不远处的鸟巢初具雏形，也到什刹海的冰场里尝试过冰上的刺激。而半年后再一次到访时，奥运的人流却已挤满了城市。还记得军事博物馆和首都博物馆的壮观，也记得世纪坛旁中央电视台的老楼。天安门已经不再新鲜，但后海的胡同依然吸引着我的注目。清华大学的食堂廉价而美味，可渺小的我早已认清了同他的距离。")]),v._v(" "),_("p",[v._v("一转眼又过去几年，我升入了初中。国庆节时，我又再一次来到北京城里。依然是熟悉的122，依然是轰鸣的老巫婆。只是四路已经不再，大一路也随之迁往了马官营。刚刚修成的北京西站南路上开过双层的72路，大观园池塘的鸭子充满活泼可爱的气息。京沪高铁的开通拉近了时空的距离，前门大街现代的铛铛车渐渐把传统抹去。飞驰的动车越过山东大地，也意味着一个时代正离我们远去。")]),v._v(" "),_("p",[v._v("再一次来到北京是七年前的夏天了，从大草原上的赤峰坐了一夜的火车来到西直门，再辗转13号线去往外公外婆在望京的新家，可随即便迷失在望京西的出站口，找不到去往花家地的路。从城西南到了城东北，现代化的望京让人迷失在高楼大厦里。南锣鼓巷的人声鼎沸里，少了些什刹海老胡同的烟火味道。不远的798街区里，是现代艺术的辉煌。")]),v._v(" "),_("p",[v._v("渐渐的，去北京不再是为了游玩，更多的是过年时一份家的味道，一种大家团圆的感觉。过年去北京住几天，看看年迈的外公外婆。熟悉的T65/66次江南明珠号，熟悉403路开往环行铁道。还记得一五年的冬天，北京下的一场雪，很美，很美。")]),v._v(" "),_("p",[v._v("可随着高中的课业压力不断增加，再到北京却已是高考后的暑假。在旅途中突发了急性肠胃炎的我拖着虚弱的身躯从沈阳来到北京，渐渐康复，渐渐能够骑着车远行。已经不会再在望京的大街小巷里迷路，也能够在脑海镌刻北京的地图。在又一个春节里，看尽了故宫的天空，和冬日的焰火。去北京读研深造的想法，渐渐成熟，却渐渐沦落。")]),v._v(" "),_("p",[v._v("转眼又是两年，曾经辉煌的T65/66已经化为了绿色的垃圾桶，轰鸣的403路财神京后也已变身各种电动。时光在变，北京也在变，可能不变的，只有那历尽沧桑的紫禁城，和那承载着繁荣与梦想的，北京青年们。")]),v._v(" "),_("p",[v._v("还记得八月长安橘生淮南的小说最后，当洛枳和盛淮南重聚在景山的山顶，看着那日暮时分华灯初上的北京城的场景。北京是什么？是清华园意气风发的学子？是金融街衣冠楚楚的白领？还是后厂村深夜时分成群结队的码农？他们都在北京，他们又都不在北京。")]),v._v(" "),_("h2",{attrs:{id:"百景·江南"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#百景·江南"}},[v._v("#")]),v._v(" 百景·江南")]),v._v(" "),_("p",[v._v("外面的雷雨依然一阵又一阵，没有停歇的意思。今年的梅雨季似乎格外的长，又格外地暴躁。暴风骤雨，电闪雷鸣，狂风阵阵，洪水涛涛。这不像我印象里的江南，但确是我生活着的江南。这生活了近十八年，却从来没有喜欢过的地方。")]),v._v(" "),_("p",[v._v("风到这里就是粘，粘住过客的思念。雨到了这里缠成线，缠着我们流连人世间。在一切的诗歌词曲间，江南都是美好富饶的地方。应天府、扬州府、苏州府、松江府、湖州府、杭州府、太平府、宁国府，是扬一益二，是无徽不成商，是上有天堂下有苏杭，是苏湖熟天下足，是买不尽的松江布收不尽的魏塘纱。经济发达的长三角，是文人墨客的梦，是无数人向往的江南水乡。")]),v._v(" "),_("p",[v._v("然而，这里的夏天也是酷暑难耐，这里的冬天湿冷彻骨。淅沥的小雨是诗意，可连绵数月的梅雨则是折磨。江南就像是一位外表美艳的姑娘，她以诱人的外表吸引着你，却也有着属于自己的大小姐脾气。就一如江南的女子，婉约而不失傲气，清丽而不失潇洒。令人一见倾心，却难以得到她的回眸。台下人走过，不见旧颜色。台上人唱着，心碎离别歌。情字难落墨，她唱须以血来和。戏幕起，戏幕落，谁是客。")]),v._v(" "),_("p",[v._v("六朝的脂粉气氤氲了秦淮河的烟波，大运河的交错织出了扬州城的繁茂。园林绣坊装点了苏州府的奢华，水漫金山书写着润州城的往事。也曾独自在江南的大地上走走停停，却总与某位网友相交在未知的巧遇。烟雨之中的洞庭西山，紫色绚烂的薰衣草谷，瑞雪缤纷的城隍庙里，灯火璀璨的七里山塘。旅途里见过的无数浪漫，终究只剩似梦非梦的回想。")]),v._v(" "),_("p",[v._v("但终究，人还是要回归于现实。再多的浪漫，也需要有人同你分享。一个人的旅途，收获的总是突然而然的感动，它可能关乎自然，但却更关乎于内心。也许是情感焦虑里的一份释然，也许是学业压力下的一份超脱，也许是沉郁之后的豁然开朗，也许是忙碌工作间的心绪恍惚。但终究，离开了那份心境，纵景致仍是那份景致，可感动也不再是感动。")]),v._v(" "),_("p",[v._v("江南百景，妙笔生花。是人铸造了江南的风景，还是江南的风景塑造了人？这似乎本就并不重要，因为最美的风景，是人。")]),v._v(" "),_("h2",{attrs:{id:"九万字"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#九万字"}},[v._v("#")]),v._v(" 九万字")]),v._v(" "),_("p",[v._v("当坊间最善舞的女儿死了，京城就该有一场大雪。")]),v._v(" "),_("p",[v._v("世上九万字，情字最伤人。")]),v._v(" "),_("p",[v._v("飘泊的雪，摇曳回风。诗意灵魂，更迭情人。总管用轻浮的茂盛，掩抹深沉。")]),v._v(" "),_("p",[v._v("网易云之所以为网抑云，是因为人世间总有那么多遗憾和不圆满，而伤情的音乐总让人相会在热评之间。也许白天散尽了快乐，深夜里剩下的总是忧伤。人总有两面性，每一个熬着夜的灵魂里，都浸润了忧郁和悲伤。")]),v._v(" "),_("p",[v._v("有谁不是，少年热诚。孑然一身，爱一个人。望尽了毕生温柔眼神。写得出最刻薄的字文，以讥诮这庸尘。却不忍，斥你毫分。")]),v._v(" "),_("p",[v._v("曾经十七岁的我，喜欢上了一个注定不属于我的人。只因北京街头看到的一眼，却再也放不下了心中的念。后海的惊鸿一瞥，半场一载的缘。所谓埋在心底的喜欢，终究还是会被有心人发现，却不如早做坦白。可是我太年轻，可是我什么都没有想好。给了我太多的机会，却终究也没有去珍惜。没有什么好去说的，错的不过是那时的自己。")]),v._v(" "),_("p",[v._v("我也算万种风情，实非良人。谁能有幸，错付终身。最先动情的人，剥去利刃，沦为人臣。我爱你苍凉双眼，明月星辰。不远万里，叩入心门。一个孤僻的唇，摘获了你首肯，献上一吻。")]),v._v(" "),_("p",[v._v("此后来到计算机系的两年里，我又认识了许许多多的人。也曾一次又一次动过念想，却从不敢把朋友的关系再进一步。沉溺在虚拟的世界，着迷于有趣的灵魂。但喜欢永远是卑微的，先动情的人，把心都都交给了对方，自己便啥都不剩。所有爱情的悲剧，总是来源于痴情者。因为他们的心里，她就是世间的唯一一抹绝色。世间的其他一切，都不再重要了。")]),v._v(" "),_("p",[v._v("越繁华的地方，独自走过的人就越感到孤独。不论是中山路珠江路南还是察院场观前街西，不论是万达金鹰还是苏州中心。当你走在这偌大的世界里，身旁是熙熙攘攘的人群，而你与世界的联系，却只剩了一部区区数寸的手机。独自一人的旅行，未必算是旅行，也许应当是修行。修行的意义，在于寻找一份独属于自己的感动。")]),v._v(" "),_("p",[v._v("喜爱在山川湖海间穿行的，或许是风吧。像风一样，无牵无挂的来，无牵无挂的去，不留下太多的踪迹。每一个孤独的人，或许会拥抱白天，但更热爱的，定是黑夜。黑夜里，世界只剩下自己，钱塘江上的空气，西子湖畔的落雨。松江清晨的第一缕朝霞，金鸡湖边最后的一丝牵挂。就连风，也有着那么些许的惬意。")]),v._v(" "),_("p",[v._v("可我还是放不下你。")]),v._v(" "),_("h2",{attrs:{id:"宣州·晴"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#宣州·晴"}},[v._v("#")]),v._v(" 宣州·晴")]),v._v(" "),_("p",[v._v("七月的尽头，越过石臼湖，南望牛头冲。")]),v._v(" "),_("p",[v._v("间歇性的伤感总是在所难免，但可以救赎。感情的惆怅在深夜间酝酿，却也不会在白天展露。该努力的时候还是得努力，尽管有的时候努力本身可能并没有过多的意义。")]),v._v(" "),_("p",[v._v("重情之人的情感是个枷锁，在找到下一个合适的人之前，这份镣铐会一直佩戴着。心中只有一个人，也永远只会有一个人。就是一份传递的执念，没有新的人来化解，它就会一直存在下去。")]),v._v(" "),_("p",[v._v("总有人劝我去说，其实大可不必。人在大四，未来大概率还是去远方发展。现在所争取的一切，到未来，谁也不知道会怎样，但大概率不美好。既然能想到结局，那为什么还要去开始呢？")]),v._v(" "),_("p",[v._v("就让这些点滴埋藏着吧。也许未来再相见时，提起曾经，无喜无悲，仅轻轻说道：那时我也曾喜欢过你。这样的结局，或许比永远不再是朋友的以后来的美好些。")]),v._v(" "),_("p",[v._v("阴雨过去，阳光出来了，未来还是会明亮的吧。")]),v._v(" "),_("p",[v._v("其实表白失败不一定做不成朋友，但我显然不是。内心打成了死结，残存的高傲也会使我主动去远离。那不如，珍惜做朋友的美好。")]),v._v(" "),_("p",[v._v("重情却又放不下残存的自尊，这可能是我未来失败悲剧的预兆吧。毕竟每一个拥有这样特质的男主，似乎都不曾有过好的结局。")])])}),[],!1,null,null,null);_.default=p.exports}}]);